VALUES
  ('public-health-specialist-moex-00597', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '依據傳染病防治法，中央各目的事業主管機關應配合及協助辦理傳染病防治事項，下列敘述 何者錯誤？', '["內政主管機關：入出國（境）管制", "經濟主管機關：防護裝備供應", "交通主管機關：漁港之管制", "勞動主管機關：勞動安全衛生及工作權保障"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00598', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '有關全民健康保險不給付範圍之項目，下列何者錯誤？', '["預防接種及其他由各級政府負擔費用之醫療服務項目", "成藥、醫師藥師藥劑生指示藥品", "精神疾病日間住院", "人體試驗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00599', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '愛滋感染者A搜尋網路得知B醫師為腹腔鏡微創手術專家，透過網路上提供的LineID聯繫 上B醫師所創建的「頂尖手術中心」群組。經群組小編C安排，A至B醫師門診就醫並排定 一星期後至D醫院進行手術。A於手術前一日辦妥住院手續後，告知病房護理師其為愛滋感 染者。隔日手術前，C通知A因為手術器械準備不及，當天手術取消，請A辦理出院手續。 上述情境所可能涉及之法律問題，下列敘述何者正確？', '["A就醫時應向醫事人員告知其已感染人類免疫缺乏病毒，A提供感染事實後，B即得依其 風險判斷，決定是否提供A醫療服務", "非醫療機構，不得使用醫療機構或類似醫療機構之名稱，若「頂尖手術中心」非醫療機構， B醫師不得使用「頂尖手術中心」之名稱招攬病人", "愛滋感染者就醫可能對醫事人員產生風險，A應至衛生福利部疾病管制署指定之人類免疫 缺乏病毒指定醫事機構，若D不是指定機構，D得拒絕A在其機構接受手術", "感染者之人格與合法權益應受尊重及保障，不得予以歧視；B 醫師以手術器械準備不及而 拒絕手術應屬正當理由，不涉及就醫歧視"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00600', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '下列何者非屬進行公共衛生計畫之倫理分析時應考量的問題？', '["公共衛生計畫或政策之目標", "達成計畫或政策目標之手段有效性", "提供公共衛生服務或其他利害關係人之合理經濟上利益", "公共衛生計畫或政策對受影響人民造成之負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00601', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '在新冠肺炎（COVID-19）大流行期間，快速且大規模地接種COVID-19疫苗對於減少感染和 結束大流行至關重要，有關達此目標之各種方法可能產生之倫理議題，下列敘述何者錯誤？', '["提供現金或禮物之接種計畫可鼓勵人民接種，但可能弱化人民接種疫苗之道德上義務，也 可能加深對疫苗的不信任", "給予完全接種者特權，例如得進入餐廳或健身房，可鼓勵人民接種，但必須考量對部分不 適合接種者產生不公平對待", "消除非法居留移工之疫苗猶豫，採取不查驗身分、不查處其非法居留事實可能比提供經濟 誘因對其自主決定影響較小且更有效", "強制接種可以快速拉高接種率，在國家提供緊急授權疫苗傷害補償的前提下，國家應針對 高風險族群實施強制接種"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00602', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關醫療機構或醫師之告知後同意義務，何者錯誤？', '["病人為無行為能力人而無法為意思表示或受意思表示時，醫療機構或醫師仍應以適當方式 告知本人", "醫療機構診治病人、實施手術或侵入性治療時，應善盡說明義務，且均應取得病人之書面 同意後始得為之", "病人自主權利法規定，醫療機構或醫師僅能在病人未明示反對時，始得將病人之病情、治 療方針、處置、預後情形等資訊告知病人之關係人，與醫師法或醫療法之規定不盡相同", "醫療機構施行人體試驗時，接受試驗者若為限制行為能力人，需同時取得本人及法定代理 人之同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00603', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關病人隱私權保障或個人資料保護之敘述，何者錯誤？', '["醫師法規定，醫師對於因業務而知悉或持有他人之病情或健康資訊不得無故洩漏，而一般 認為若醫師依據相關法令規定提供病人資訊，應不構成「無故」而可成立阻卻違法之事由", "個人資料保護法第6條第1項規定病歷、醫療、基因、性生活、健康檢查及犯罪前科之個 人資料，原則上不得蒐集、處理或利用，除非有法定例外情形", "中央健康保險署在事前未徵詢當事人同意、事後不允許退出之前提下，提供個人健康保險 資料予學術研究機構於原始蒐集目的外進行學術研究，因相關資料已經去識別化而無法識 別特定個人，故對個人權利並無侵害", "通訊診察治療辦法規定通訊診療之實施仍應確保病患隱私權保護，包括相關過程應於醫療 機構內實施"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00604', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '以下有關人體研究之敘述，何者正確？', '["人體研究法規範之人體檢體範圍僅包括人體器官、組織、細胞或體液，並不包括經實驗操 作產生之衍生物質", "人體研究於二個以上研究機構實施時，除非各研究機構有共同約定之倫理審查委員會，否 則各該研究機構之倫理審查委員會均應加以審查", "以研究原住民族為目的之人體研究，若不是在原住民族土地、部落或其周邊一定範圍內之 公有土地進行，便不需要諮詢並取得原住民族之同意", "使用未去連結之研究材料，逾越原應以書面同意使用範圍時，研究者可逕行將該研究材料 去連結，便不需要再經過告知研究參與者並取得同意之程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00605', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '在憲法中，有關公共衛生之內容，下列何者正確？', '["公共衛生事項，依地方自治精神，由地方立法並執行之", "公共衛生事項，由中央立法，並交由省縣執行之", "公共衛生事項，由中央立法並執行之，或交由省縣執行之", "憲法中並未出現「公共衛生」文字"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00606', 'public-health-specialist', 'public-health-specialist-moex-112-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '下列何者不屬於公共衛生政策的一般倫理考量？', '["利益", "尊重自主選擇與行動", "保護隱私及機密資訊", "落實結果正義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "48f117d43f53", "answer_pdf_sha1": "588d00f5aaa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
